import time
import uuid
import heapq
import threading
from enum import Enum
from dataclasses import dataclass, field
from typing import Optional
from collections import defaultdict
from datetime import datetime, timedelta


class TaskStatus(Enum):
    PENDING = "pending"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"
    FAILED = "failed"
    REASSIGNED = "reassigned"
    CANCELLED = "cancelled"


class AgentStatus(Enum):
    AVAILABLE = "available"
    BUSY = "busy"
    UNAVAILABLE = "unavailable"


class Priority(Enum):
    LOW = 1
    MEDIUM = 2
    HIGH = 3
    CRITICAL = 4

    def __lt__(self, other):
        return self.value < other.value


@dataclass
class Message:
    sender_id: str
    receiver_id: str
    content: str
    timestamp: datetime = field(default_factory=datetime.now)
    message_id: str = field(default_factory=lambda: str(uuid.uuid4()))


@dataclass
class TaskHistoryEntry:
    timestamp: datetime
    event: str
    agent_id: Optional[str] = None
    notes: str = ""


@dataclass
class Task:
    name: str
    description: str
    priority: Priority
    required_resources: list = field(default_factory=list)
    task_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    status: TaskStatus = TaskStatus.PENDING
    assigned_agents: list = field(default_factory=list)
    progress: float = 0.0
    estimated_completion: Optional[datetime] = None
    created_at: datetime = field(default_factory=datetime.now)
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    issues: list = field(default_factory=list)
    history: list = field(default_factory=list)
    notes: list = field(default_factory=list)

    def __lt__(self, other):
        return self.priority.value > other.priority.value

    def add_history(self, event: str, agent_id: Optional[str] = None, notes: str = ""):
        entry = TaskHistoryEntry(
            timestamp=datetime.now(), event=event, agent_id=agent_id, notes=notes
        )
        self.history.append(entry)


@dataclass
class Agent:
    name: str
    capabilities: list = field(default_factory=list)
    agent_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    status: AgentStatus = AgentStatus.AVAILABLE
    current_tasks: list = field(default_factory=list)
    max_concurrent_tasks: int = 3
    performance_score: float = 1.0
    messages: list = field(default_factory=list)

    @property
    def available_capacity(self) -> int:
        return self.max_concurrent_tasks - len(self.current_tasks)

    @property
    def is_available(self) -> bool:
        return self.status == AgentStatus.AVAILABLE and self.available_capacity > 0


class CommunicationHub:
    """Handles inter-agent communication and shared status updates."""

    def __init__(self):
        self._messages: list = []
        self._broadcast_log: list = []
        self._subscribers: dict = defaultdict(list)
        self._lock = threading.Lock()

    def send_message(self, sender_id: str, receiver_id: str, content: str) -> Message:
        msg = Message(sender_id=sender_id, receiver_id=receiver_id, content=content)
        with self._lock:
            self._messages.append(msg)
        return msg

    def broadcast(self, sender_id: str, content: str) -> Message:
        msg = Message(sender_id=sender_id, receiver_id="ALL", content=content)
        with self._lock:
            self._broadcast_log.append(msg)
        return msg

    def get_messages_for(self, agent_id: str) -> list:
        with self._lock:
            return [
                m
                for m in self._messages
                if m.receiver_id == agent_id or m.receiver_id == "ALL"
            ]

    def get_broadcasts(self, since: Optional[datetime] = None) -> list:
        with self._lock:
            if since:
                return [m for m in self._broadcast_log if m.timestamp >= since]
            return list(self._broadcast_log)

    def subscribe(self, agent_id: str, event_type: str):
        self._subscribers[event_type].append(agent_id)

    def notify_subscribers(self, event_type: str, content: str):
        for agent_id in self._subscribers.get(event_type, []):
            self.send_message("SYSTEM", agent_id, content)


class TaskQueue:
    """Priority-based task queue with dynamic reordering."""

    def __init__(self):
        self._queue: list = []
        self._lock = threading.Lock()

    def push(self, task: Task):
        with self._lock:
            heapq.heappush(self._queue, (-task.priority.value, task.created_at, task))

    def pop(self) -> Optional[Task]:
        with self._lock:
            if self._queue:
                _, _, task = heapq.heappop(self._queue)
                return task
            return None

    def peek(self) -> Optional[Task]:
        with self._lock:
            if self._queue:
                return self._queue[0][2]
            return None

    def remove(self, task_id: str) -> Optional[Task]:
        with self._lock:
            for i, (_, _, task) in enumerate(self._queue):
                if task.task_id == task_id:
                    self._queue.pop(i)
                    heapq.heapify(self._queue)
                    return task
            return None

    def reorder(self):
        with self._lock:
            heapq.heapify(self._queue)

    @property
    def size(self) -> int:
        return len(self._queue)

    @property
    def tasks(self) -> list:
        with self._lock:
            return [task for _, _, task in self._queue]


class MultiAgentTaskScheduler:
    """
    Coordinates and executes tasks among multiple agents with dynamic
    scheduling, real-time feedback, and adaptive reorganization.
    """

    def __init__(self):
        self._agents: dict = {}
        self._tasks: dict = {}
        self._task_queue = TaskQueue()
        self._communication = CommunicationHub()
        self._history: list = []
        self._lock = threading.Lock()
        self._running = False
        self._scheduler_thread: Optional[threading.Thread] = None
        self._callbacks: dict = defaultdict(list)

    # --- Agent Management ---

    def register_agent(self, name: str, capabilities: Optional[list] = None,
                       max_concurrent: int = 3) -> Agent:
        agent = Agent(
            name=name,
            capabilities=capabilities or [],
            max_concurrent_tasks=max_concurrent,
        )
        self._agents[agent.agent_id] = agent
        self._communication.broadcast(
            "SYSTEM", f"Agent '{name}' registered (id={agent.agent_id})"
        )
        self._trigger_event("agent_registered", agent)
        return agent

    def remove_agent(self, agent_id: str):
        agent = self._agents.get(agent_id)
        if not agent:
            raise ValueError(f"Agent {agent_id} not found")
        agent.status = AgentStatus.UNAVAILABLE
        tasks_to_reassign = list(agent.current_tasks)
        for task_id in tasks_to_reassign:
            self._reassign_task(task_id, reason="Agent became unavailable")
        del self._agents[agent_id]
        self._communication.broadcast(
            "SYSTEM", f"Agent '{agent.name}' removed; tasks reassigned"
        )

    def set_agent_status(self, agent_id: str, status: AgentStatus):
        agent = self._agents.get(agent_id)
        if not agent:
            raise ValueError(f"Agent {agent_id} not found")
        old_status = agent.status
        agent.status = status
        if status == AgentStatus.UNAVAILABLE and old_status != AgentStatus.UNAVAILABLE:
            for task_id in list(agent.current_tasks):
                self._reassign_task(task_id, reason="Agent unavailable")
        elif status == AgentStatus.AVAILABLE and old_status != AgentStatus.AVAILABLE:
            self._try_assign_pending_tasks()
        self._trigger_event("agent_status_changed", agent, old_status, status)

    def get_agent(self, agent_id: str) -> Optional[Agent]:
        return self._agents.get(agent_id)

    def list_agents(self, status_filter: Optional[AgentStatus] = None) -> list:
        agents = list(self._agents.values())
        if status_filter:
            agents = [a for a in agents if a.status == status_filter]
        return agents

    # --- Task Management ---

    def create_task(self, name: str, description: str, priority: Priority,
                    required_resources: Optional[list] = None,
                    estimated_duration: Optional[timedelta] = None) -> Task:
        task = Task(
            name=name,
            description=description,
            priority=priority,
            required_resources=required_resources or [],
        )
        if estimated_duration:
            task.estimated_completion = datetime.now() + estimated_duration
        task.add_history("Task created")
        self._tasks[task.task_id] = task
        self._task_queue.push(task)
        self._communication.broadcast(
            "SYSTEM", f"New task '{name}' (priority={priority.name}) added"
        )
        self._communication.notify_subscribers(
            "new_task", f"New task available: {name}"
        )
        self._trigger_event("task_created", task)
        self._try_assign_pending_tasks()
        return task

    def cancel_task(self, task_id: str, reason: str = ""):
        task = self._tasks.get(task_id)
        if not task:
            raise ValueError(f"Task {task_id} not found")
        task.status = TaskStatus.CANCELLED
        task.add_history("Task cancelled", notes=reason)
        self._task_queue.remove(task_id)
        for agent_id in task.assigned_agents:
            agent = self._agents.get(agent_id)
            if agent and task_id in agent.current_tasks:
                agent.current_tasks.remove(task_id)
        self._communication.broadcast(
            "SYSTEM", f"Task '{task.name}' cancelled: {reason}"
        )
        self._trigger_event("task_cancelled", task)

    def update_task_progress(self, task_id: str, progress: float,
                             agent_id: Optional[str] = None,
                             notes: str = ""):
        task = self._tasks.get(task_id)
        if not task:
            raise ValueError(f"Task {task_id} not found")
        task.progress = min(max(progress, 0.0), 100.0)
        task.add_history(
            f"Progress updated to {task.progress:.1f}%",
            agent_id=agent_id,
            notes=notes,
        )
        if task.progress >= 100.0:
            self._complete_task(task_id, agent_id)
        self._trigger_event("task_progress", task)

    def report_issue(self, task_id: str, issue: str, agent_id: Optional[str] = None):
        task = self._tasks.get(task_id)
        if not task:
            raise ValueError(f"Task {task_id} not found")
        task.issues.append({"issue": issue, "reported_by": agent_id,
                            "timestamp": datetime.now()})
        task.add_history("Issue reported", agent_id=agent_id, notes=issue)
        self._communication.broadcast(
            "SYSTEM", f"Issue on task '{task.name}': {issue}"
        )
        self._trigger_event("task_issue", task, issue)

    def get_task(self, task_id: str) -> Optional[Task]:
        return self._tasks.get(task_id)

    # --- Task Assignment ---

    def assign_task(self, task_id: str, agent_id: str) -> bool:
        task = self._tasks.get(task_id)
        agent = self._agents.get(agent_id)
        if not task or not agent:
            return False
        if not agent.is_available:
            return False
        task.assigned_agents.append(agent_id)
        task.status = TaskStatus.IN_PROGRESS
        task.started_at = task.started_at or datetime.now()
        task.add_history("Assigned to agent", agent_id=agent_id)
        agent.current_tasks.append(task_id)
        if agent.available_capacity == 0:
            agent.status = AgentStatus.BUSY
        self._task_queue.remove(task_id)
        self._communication.send_message(
            "SYSTEM", agent_id, f"Task '{task.name}' assigned to you"
        )
        self._trigger_event("task_assigned", task, agent)
        return True

    def _reassign_task(self, task_id: str, reason: str = ""):
        task = self._tasks.get(task_id)
        if not task:
            return
        old_agents = list(task.assigned_agents)
        for aid in old_agents:
            agent = self._agents.get(aid)
            if agent and task_id in agent.current_tasks:
                agent.current_tasks.remove(task_id)
                if agent.status == AgentStatus.BUSY and agent.available_capacity > 0:
                    agent.status = AgentStatus.AVAILABLE
        task.assigned_agents.clear()
        task.status = TaskStatus.REASSIGNED
        task.add_history("Task reassigned", notes=reason)
        self._task_queue.push(task)
        for aid in old_agents:
            self._communication.send_message(
                "SYSTEM", aid, f"Task '{task.name}' reassigned: {reason}"
            )
        self._try_assign_pending_tasks()
        self._trigger_event("task_reassigned", task)

    def _try_assign_pending_tasks(self):
        available_agents = [a for a in self._agents.values() if a.is_available]
        if not available_agents:
            return
        pending_tasks = [
            t for t in self._task_queue.tasks
            if t.status in (TaskStatus.PENDING, TaskStatus.REASSIGNED)
        ]
        for task in sorted(pending_tasks, key=lambda t: -t.priority.value):
            best_agent = self._find_best_agent(task, available_agents)
            if best_agent:
                self.assign_task(task.task_id, best_agent.agent_id)
                if not best_agent.is_available:
                    available_agents.remove(best_agent)
            if not available_agents:
                break

    def _find_best_agent(self, task: Task, candidates: list) -> Optional[Agent]:
        scored = []
        for agent in candidates:
            if not agent.is_available:
                continue
            score = agent.performance_score
            if task.required_resources:
                match = len(set(task.required_resources) & set(agent.capabilities))
                score += match * 0.5
            score += agent.available_capacity * 0.1
            scored.append((score, agent))
        if scored:
            scored.sort(key=lambda x: -x[0])
            return scored[0][1]
        return None

    def _complete_task(self, task_id: str, agent_id: Optional[str] = None):
        task = self._tasks.get(task_id)
        if not task:
            return
        task.status = TaskStatus.COMPLETED
        task.progress = 100.0
        task.completed_at = datetime.now()
        task.add_history("Task completed", agent_id=agent_id)
        for aid in task.assigned_agents:
            agent = self._agents.get(aid)
            if agent:
                if task_id in agent.current_tasks:
                    agent.current_tasks.remove(task_id)
                if agent.status == AgentStatus.BUSY and agent.available_capacity > 0:
                    agent.status = AgentStatus.AVAILABLE
                agent.performance_score = min(agent.performance_score + 0.05, 2.0)
        self._history.append(task)
        self._communication.broadcast(
            "SYSTEM", f"Task '{task.name}' completed!"
        )
        self._trigger_event("task_completed", task)
        self._try_assign_pending_tasks()

    # --- Querying and Filtering ---

    def search_tasks(self, query: str) -> list:
        query_lower = query.lower()
        return [
            t for t in self._tasks.values()
            if query_lower in t.name.lower() or query_lower in t.description.lower()
        ]

    def filter_tasks(self, status: Optional[TaskStatus] = None,
                     priority: Optional[Priority] = None,
                     agent_id: Optional[str] = None) -> list:
        results = list(self._tasks.values())
        if status:
            results = [t for t in results if t.status == status]
        if priority:
            results = [t for t in results if t.priority == priority]
        if agent_id:
            results = [t for t in results if agent_id in t.assigned_agents]
        return results

    def sort_tasks(self, tasks: list, key: str = "priority",
                   reverse: bool = True) -> list:
        sort_keys = {
            "priority": lambda t: t.priority.value,
            "name": lambda t: t.name.lower(),
            "created": lambda t: t.created_at,
            "progress": lambda t: t.progress,
            "status": lambda t: t.status.value,
        }
        sort_fn = sort_keys.get(key, sort_keys["priority"])
        return sorted(tasks, key=sort_fn, reverse=reverse)

    # --- Real-time Feedback ---

    def get_task_status(self, task_id: str) -> dict:
        task = self._tasks.get(task_id)
        if not task:
            return {}
        eta = None
        if task.started_at and task.progress > 0:
            elapsed = (datetime.now() - task.started_at).total_seconds()
            total_estimated = elapsed / (task.progress / 100.0)
            remaining = total_estimated - elapsed
            eta = datetime.now() + timedelta(seconds=max(remaining, 0))
        return {
            "task_id": task.task_id,
            "name": task.name,
            "status": task.status.value,
            "progress": task.progress,
            "assigned_agents": task.assigned_agents,
            "estimated_completion": eta,
            "issues": task.issues,
            "started_at": task.started_at,
        }

    def get_agent_performance(self, agent_id: str) -> dict:
        agent = self._agents.get(agent_id)
        if not agent:
            return {}
        completed = [
            t for t in self._history if agent_id in t.assigned_agents
        ]
        return {
            "agent_id": agent.agent_id,
            "name": agent.name,
            "status": agent.status.value,
            "current_tasks": len(agent.current_tasks),
            "completed_tasks": len(completed),
            "performance_score": agent.performance_score,
            "capacity": agent.available_capacity,
        }

    # --- Communication ---

    def send_message(self, from_id: str, to_id: str, content: str) -> Message:
        return self._communication.send_message(from_id, to_id, content)

    def broadcast_message(self, from_id: str, content: str) -> Message:
        return self._communication.broadcast(from_id, content)

    def get_agent_messages(self, agent_id: str) -> list:
        return self._communication.get_messages_for(agent_id)

    # --- History ---

    def get_task_history(self, task_id: str) -> list:
        task = self._tasks.get(task_id)
        if not task:
            return []
        return task.history

    def get_completed_tasks(self) -> list:
        return list(self._history)

    def get_full_history_log(self) -> list:
        log = []
        for task in self._tasks.values():
            entry = {
                "task_id": task.task_id,
                "name": task.name,
                "status": task.status.value,
                "priority": task.priority.name,
                "created_at": task.created_at,
                "started_at": task.started_at,
                "completed_at": task.completed_at,
                "assigned_agents": [
                    self._agents[a].name
                    for a in task.assigned_agents
                    if a in self._agents
                ],
                "issues": task.issues,
                "notes": task.notes,
                "history": [
                    {
                        "timestamp": h.timestamp,
                        "event": h.event,
                        "agent": h.agent_id,
                        "notes": h.notes,
                    }
                    for h in task.history
                ],
            }
            log.append(entry)
        return log

    # --- Event System ---

    def on(self, event_type: str, callback):
        self._callbacks[event_type].append(callback)

    def _trigger_event(self, event_type: str, *args):
        for cb in self._callbacks.get(event_type, []):
            try:
                cb(*args)
            except Exception:
                pass

    # --- Scheduler Loop ---

    def start(self):
        self._running = True
        self._scheduler_thread = threading.Thread(
            target=self._scheduler_loop, daemon=True
        )
        self._scheduler_thread.start()

    def stop(self):
        self._running = False
        if self._scheduler_thread:
            self._scheduler_thread.join(timeout=2)

    def _scheduler_loop(self):
        while self._running:
            self._try_assign_pending_tasks()
            time.sleep(1)

    # --- Dashboard / Interface ---

    def dashboard(self) -> dict:
        total = len(self._tasks)
        by_status = defaultdict(int)
        for t in self._tasks.values():
            by_status[t.status.value] += 1
        agents_summary = []
        for a in self._agents.values():
            agents_summary.append({
                "name": a.name,
                "status": a.status.value,
                "tasks": len(a.current_tasks),
                "score": a.performance_score,
            })
        return {
            "total_tasks": total,
            "tasks_by_status": dict(by_status),
            "pending_queue_size": self._task_queue.size,
            "agents": agents_summary,
            "completed_count": len(self._history),
        }


# --- CLI Interface ---

def run_interactive():
    """Simple command-line interface for the scheduler."""
    scheduler = MultiAgentTaskScheduler()
    scheduler.start()

    print("=" * 60)
    print("  MultiAgentTaskScheduler - Interactive Mode")
    print("=" * 60)
    print("\nCommands: add-agent, add-task, assign, progress, status,")
    print("          search, filter, agents, dashboard, history,")
    print("          message, quit\n")

    while True:
        try:
            cmd = input("> ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            break

        if cmd == "quit":
            break
        elif cmd == "add-agent":
            name = input("  Agent name: ").strip()
            caps = input("  Capabilities (comma-sep): ").strip()
            capabilities = [c.strip() for c in caps.split(",") if c.strip()]
            agent = scheduler.register_agent(name, capabilities)
            print(f"  Registered: {agent.name} ({agent.agent_id[:8]}...)")
        elif cmd == "add-task":
            name = input("  Task name: ").strip()
            desc = input("  Description: ").strip()
            pri = input("  Priority (low/medium/high/critical): ").strip().upper()
            priority = Priority[pri] if pri in Priority.__members__ else Priority.MEDIUM
            resources = input("  Resources (comma-sep): ").strip()
            res_list = [r.strip() for r in resources.split(",") if r.strip()]
            task = scheduler.create_task(name, desc, priority, res_list)
            print(f"  Created: {task.name} ({task.task_id[:8]}...)")
        elif cmd == "assign":
            tid = input("  Task ID (prefix): ").strip()
            aid = input("  Agent ID (prefix): ").strip()
            task_match = next(
                (t for t in scheduler._tasks if t.startswith(tid)), None
            )
            agent_match = next(
                (a for a in scheduler._agents if a.startswith(aid)), None
            )
            if task_match and agent_match:
                ok = scheduler.assign_task(task_match, agent_match)
                print(f"  {'Assigned' if ok else 'Failed'}")
            else:
                print("  Task or agent not found")
        elif cmd == "progress":
            tid = input("  Task ID (prefix): ").strip()
            pct = float(input("  Progress %: ").strip())
            task_match = next(
                (t for t in scheduler._tasks if t.startswith(tid)), None
            )
            if task_match:
                scheduler.update_task_progress(task_match, pct)
                print(f"  Updated to {pct}%")
            else:
                print("  Task not found")
        elif cmd == "status":
            tid = input("  Task ID (prefix): ").strip()
            task_match = next(
                (t for t in scheduler._tasks if t.startswith(tid)), None
            )
            if task_match:
                s = scheduler.get_task_status(task_match)
                print(f"  {s['name']}: {s['status']} ({s['progress']:.1f}%)")
                if s.get("estimated_completion"):
                    print(f"  ETA: {s['estimated_completion']}")
        elif cmd == "search":
            q = input("  Query: ").strip()
            results = scheduler.search_tasks(q)
            for t in results:
                print(f"  [{t.priority.name}] {t.name} - {t.status.value}")
        elif cmd == "filter":
            st = input("  Status (or blank): ").strip()
            status = TaskStatus(st) if st else None
            results = scheduler.filter_tasks(status=status)
            for t in results:
                print(f"  [{t.priority.name}] {t.name} - {t.status.value}")
        elif cmd == "agents":
            for a in scheduler.list_agents():
                print(
                    f"  {a.name} ({a.agent_id[:8]}...) "
                    f"- {a.status.value} | tasks: {len(a.current_tasks)}"
                )
        elif cmd == "dashboard":
            d = scheduler.dashboard()
            print(f"  Total tasks: {d['total_tasks']}")
            print(f"  Pending queue: {d['pending_queue_size']}")
            print(f"  Completed: {d['completed_count']}")
            for s, c in d['tasks_by_status'].items():
                print(f"    {s}: {c}")
            print("  Agents:")
            for ag in d['agents']:
                print(f"    {ag['name']}: {ag['status']} (score={ag['score']:.2f})")
        elif cmd == "history":
            log = scheduler.get_full_history_log()
            for entry in log[-10:]:
                print(
                    f"  {entry['name']} [{entry['priority']}] "
                    f"- {entry['status']} | agents: {entry['assigned_agents']}"
                )
        elif cmd == "message":
            fr = input("  From agent ID (prefix): ").strip()
            to = input("  To agent ID (prefix): ").strip()
            content = input("  Message: ").strip()
            from_match = next(
                (a for a in scheduler._agents if a.startswith(fr)), None
            )
            to_match = next(
                (a for a in scheduler._agents if a.startswith(to)), None
            )
            if from_match and to_match:
                scheduler.send_message(from_match, to_match, content)
                print("  Sent")
            else:
                print("  Agent not found")
        else:
            print("  Unknown command. Try: add-agent, add-task, assign, "
                  "progress, status, search, filter, agents, dashboard, "
                  "history, message, quit")

    scheduler.stop()
    print("Scheduler stopped.")


if __name__ == "__main__":
    run_interactive()
